import subprocess

def process_images(dirpath):
    files = []
    for path, _, filenames in os.walk(dirpath):
        for f in filenames:
            if f.endswith('.jpg'):
                files.append(os.path.join(path, f))

    for infile in files:
        outfile = infile + '.thumb'

        subprocess.run(['convert', infile, '-thumbnail', '200x200>', outfile])
        os.chmod(outfile, 0o2777)

