def select_seating_chart(total_guests, tables, table_capacities):
    max_capacity = sum(table_capacities)
    if total_guests > max_capacity:
        raise ValueError('More guests than available seats')
    elif total_guests <= 0:
        raise ValueError('No guests to seat')
    else:
        tables_needed = ceil(total_guests / min(table_capacities))
        if tables_needed > tables:
            raise ValueError('Not enough tables')
        else:
            return tables_needed

