import os

def get_next_job():

    def search_for_jobs():
        size = os.stat('job_queue').st_size
        if size < 100:
            status = os.lstat('job_queue')
            return status.st_mtime
        else:
            return None

    def get_job():
        with open('job_queue', 'r') as f:
            return f.readline().strip()


    timestamp = search_for_jobs()
    if timestamp:
        os.chmod('job_queue', 0o666)

        job = get_job()

        return job

    else:
        return None


print(get_next_job())
